#include "rate_limiter.h"
static uint32_t _interval=1000;static unsigned long _last=0;
void rate_limit_setup(uint32_t ms){_interval=ms;_last=0;}
bool rate_limit_check(){if(millis()-_last>=_interval){_last=millis();return true;}return false;}
void rate_limit_reset(){_last=0;}
